2023-03-01多继承// SPDX-License-Identifier: MITpragma solidity ^0.8.17;/* Graph of inheritance    A   / \  B   C / \ /F  D,E*/contract A &#123;    //需要被重写的函数加上virtual修饰符    function foo() public pure virtual returns(string memory) &#123;        return &quot;A&quot;;    &#125;&#125;contract B is A&#123;    function foo() public pure override virtual returns (string memory) &#123;        return &quot;B&quot;;    &#125;&#125;contract C is A &#123;    function foo() public pure override virtual returns (string memory) &#123;        return &quot;C&quot;;    &#125;&#125;// Contracts can inherit from multiple parent contracts.// When a function is called that is defined multiple times in// different contracts, parent contracts are searched from// right to left, and in depth-first manner.//合同可以多重继承//在不同合约中当函数被定义为多重继承时，父合约会自右向左，按照深度优先搜索contract D is B, C &#123;    //多继承时候需要给override传入重写合约    function foo() public pure override(B, C)  returns (string memory) &#123;        return super.foo();//返回“C”    &#125;&#125;contract E is C,B &#123;    function foo() public pure override(C, B)  returns (string memory) &#123;        return super.foo();//返回“B”    &#125;&#125;contract F is A, B &#123;        //必须把父合同放前面（A是B的父合同）        //此时是孙子合同        //调换A跟B会发生编译错误    function foo() public pure override(B, A) returns (string memory) &#123;        return super.foo();    &#125;&#125;

