// SPDX-License-Identifier: GPL-3.0pragma solidity &gt;=0.7.0 &lt;0.9.0;contract D &#123;    uint public x;    constructor(uint a) &#123;        x = a;    &#125;&#125;contract C &#123;    function createDSalted(bytes32 salt, uint arg) public &#123;        // This complicated expression just tells you how the address        // can be pre-computed. It is just there for illustration.        // You actually only need ``new D&#123;salt: salt&#125;(arg)``.        //这些复杂的表达只是告诉我们地址是如何被提前计算的，仅作展示        //事实上只需要``(new D)&#123;salt: salt&#125;(arg)``        address predictedAddress = address(uint160(uint(keccak256(abi.encodePacked(            bytes1(0xff),            address(this),            salt,            keccak256(abi.encodePacked(                type(D).creationCode,                abi.encode(arg)            ))        )))));        D d = new D&#123;salt: salt&#125;(arg);        require(address(d) == predictedAddress);    &#125;&#125;

